20		CustomerID string `json:"customer_id"`
21		ProviderID string `json:"provider_id"`
22		ServiceID  string `json:"service_id"`
23		Status     string `json:"status"`
24		CreatedAt  string `json:"created_at"`
25		UpdatedAt  string `json:"updated_at"`
