108	// Submit creates a new interest from a customer to a provider for a service.
109	func (s *Service) Submit(ctx context.Context, customerProfileID, providerProfileID, serviceID, actorID string) (*Interest, error) {
110		// Resolve user IDs for block check
111		customerUserID, err := s.GetCustomerUserID(ctx, customerProfileID)
112		if err != nil {
113			return nil, err
114		}
115		providerUserID, err := s.GetProviderUserID(ctx, providerProfileID)
116		if err != nil {
117			return nil, err
118		}
119	
120		// Check blocks
121		blocked, err := s.blocks.IsBlocked(ctx, customerUserID, providerUserID)
122		if err != nil {
123			return nil, err
124		}
125		if blocked {
126			return nil, httpx.NewForbiddenError("blocked")
127		}
128	
129		// Check duplicate within 7 days
130		var count int
131		err = s.db.QueryRowContext(ctx,
132			`SELECT COUNT(*) FROM interests WHERE customer_id=$1 AND provider_id=$2 AND status IN ('submitted','accepted') AND created_at > NOW() - INTERVAL '7 days'`,
133			customerProfileID, providerProfileID,
134		).Scan(&count)
135		if err != nil {
136			return nil, fmt.Errorf("interests: check duplicate: %w", err)
137		}
138		if count > 0 {
139			return nil, &echo.HTTPError{
140				Code: http.StatusConflict,
141				Message: httpx.APIError{
142					Error: httpx.ErrorBody{
143						Code:    "duplicate_interest",
144						Message: "An active interest already exists for this provider.",
145						FieldErrors: map[string][]string{
146							"provider_id": {"Only one active interest is allowed within 7 days."},
147						},
148					},
149				},
150			}
151		}
152	
153		// Insert interest
154		var interest Interest
155		err = s.db.QueryRowContext(ctx,
156			`INSERT INTO interests (customer_id, provider_id, service_id) VALUES ($1, $2, $3) RETURNING id, customer_id, provider_id, service_id, status, created_at::text, updated_at::text`,
157			customerProfileID, providerProfileID, serviceID,
158		).Scan(&interest.ID, &interest.CustomerID, &interest.ProviderID, &interest.ServiceID, &interest.Status, &interest.CreatedAt, &interest.UpdatedAt)
159		if err != nil {
160			return nil, fmt.Errorf("interests: insert: %w", err)
161		}
162	
163		// Insert initial status event
164		_, err = s.db.ExecContext(ctx,
165			`INSERT INTO interest_status_events (interest_id, old_status, new_status) VALUES ($1, NULL, 'submitted')`,
166			interest.ID,
167		)
168		if err != nil {
169			return nil, fmt.Errorf("interests: insert status event: %w", err)
170		}
171	
172		// Audit
173		s.audit.Log(ctx, audit.Event{
174			EventType:    "interest_submitted",
175			ActorID:      actorID,
176			ResourceType: "interest",
177			ResourceID:   interest.ID,
178			Metadata: map[string]interface{}{
179				"customer_id": customerProfileID,
180				"provider_id": providerProfileID,
181				"service_id":  serviceID,
182			},
183		})
184	
185		return &interest, nil
186	}
