188	// ListCustomer returns all interests for a customer, newest first.
189	func (s *Service) ListCustomer(ctx context.Context, customerProfileID string) ([]Interest, error) {
190		rows, err := s.db.QueryContext(ctx,
191			`SELECT id, customer_id, provider_id, service_id, status, created_at::text, updated_at::text FROM interests WHERE customer_id=$1 ORDER BY created_at DESC`,
192			customerProfileID,
193		)
194		if err != nil {
195			return nil, fmt.Errorf("interests: list customer: %w", err)
196		}
197		defer rows.Close()
198	
199		interests := make([]Interest, 0)
200		for rows.Next() {
201			var i Interest
202			if err := rows.Scan(&i.ID, &i.CustomerID, &i.ProviderID, &i.ServiceID, &i.Status, &i.CreatedAt, &i.UpdatedAt); err != nil {
203				return nil, fmt.Errorf("interests: scan: %w", err)
204			}
205			interests = append(interests, i)
206		}
207		return interests, rows.Err()
208	}
