210	// GetCustomer returns a single interest with its status events, scoped to a customer.
211	func (s *Service) GetCustomer(ctx context.Context, interestID, customerProfileID string) (*Interest, []StatusEvent, error) {
212		var interest Interest
213		err := s.db.QueryRowContext(ctx,
214			`SELECT id, customer_id, provider_id, service_id, status, created_at::text, updated_at::text FROM interests WHERE id=$1 AND customer_id=$2`,
215			interestID, customerProfileID,
216		).Scan(&interest.ID, &interest.CustomerID, &interest.ProviderID, &interest.ServiceID, &interest.Status, &interest.CreatedAt, &interest.UpdatedAt)
217		if err == sql.ErrNoRows {
218			return nil, nil, httpx.NewNotFoundError("Interest not found.")
219		}
220		if err != nil {
221			return nil, nil, fmt.Errorf("interests: get customer: %w", err)
222		}
223	
224		rows, err := s.db.QueryContext(ctx,
225			`SELECT id, old_status, new_status, created_at::text FROM interest_status_events WHERE interest_id=$1 ORDER BY created_at`,
226			interestID,
227		)
228		if err != nil {
229			return nil, nil, fmt.Errorf("interests: list events: %w", err)
230		}
231		defer rows.Close()
232	
233		events := make([]StatusEvent, 0)
234		for rows.Next() {
235			var e StatusEvent
236			if err := rows.Scan(&e.ID, &e.OldStatus, &e.NewStatus, &e.CreatedAt); err != nil {
237				return nil, nil, fmt.Errorf("interests: scan event: %w", err)
238			}
239			events = append(events, e)
240		}
241		if err := rows.Err(); err != nil {
242			return nil, nil, fmt.Errorf("interests: iterate events: %w", err)
243		}
244	
245		return &interest, events, nil
246	}
