248	// Withdraw withdraws an interest (customer action).
249	func (s *Service) Withdraw(ctx context.Context, interestID, customerProfileID, actorID string) error {
250		var status string
251		err := s.db.QueryRowContext(ctx,
252			`SELECT status FROM interests WHERE id=$1 AND customer_id=$2`,
253			interestID, customerProfileID,
254		).Scan(&status)
255		if err == sql.ErrNoRows {
256			return httpx.NewNotFoundError("Interest not found.")
257		}
258		if err != nil {
259			return fmt.Errorf("interests: withdraw lookup: %w", err)
260		}
261	
262		if status != "submitted" && status != "accepted" {
263			return httpx.NewAPIError(http.StatusUnprocessableEntity, "invalid_transition", "Cannot withdraw an interest with status '"+status+"'.")
264		}
265	
266		_, err = s.db.ExecContext(ctx,
267			`UPDATE interests SET status='withdrawn', updated_at=NOW() WHERE id=$1`,
268			interestID,
269		)
270		if err != nil {
271			return fmt.Errorf("interests: withdraw update: %w", err)
272		}
273	
274		_, err = s.db.ExecContext(ctx,
275			`INSERT INTO interest_status_events (interest_id, old_status, new_status) VALUES ($1, $2, 'withdrawn')`,
276			interestID, status,
277		)
278		if err != nil {
279			return fmt.Errorf("interests: withdraw event: %w", err)
280		}
281	
282		s.audit.Log(ctx, audit.Event{
283			EventType:    "interest_withdrawn",
284			ActorID:      actorID,
285			ResourceType: "interest",
286			ResourceID:   interestID,
287		})
288	
289		return nil
290	}
