404	// HandleCustomerSubmit handles POST /customer/interests.
405	func (s *Service) HandleCustomerSubmit(c echo.Context) error {
406		user := auth.UserFromContext(c)
407		if user == nil {
408			return httpx.NewAPIError(http.StatusUnauthorized, "unauthenticated", "Authentication required.")
409		}
410	
411		var body struct {
412			ServiceID  string `json:"service_id"`
413			ProviderID string `json:"provider_id"`
414		}
415		if err := c.Bind(&body); err != nil {
416			return httpx.NewValidationError(map[string][]string{"body": {"Invalid request body."}})
417		}
418	
419		fieldErrors := map[string][]string{}
420		if body.ServiceID == "" {
421			fieldErrors["service_id"] = []string{"Service ID is required."}
422		}
423		if body.ProviderID == "" {
424			fieldErrors["provider_id"] = []string{"Provider ID is required."}
425		}
426		if len(fieldErrors) > 0 {
427			return httpx.NewValidationError(fieldErrors)
428		}
429	
430		cpID, err := s.GetCustomerProfileID(c.Request().Context(), user.ID)
431		if err != nil {
432			return err
433		}
434	
435		interest, err := s.Submit(c.Request().Context(), cpID, body.ProviderID, body.ServiceID, user.ID)
436		if err != nil {
437			return err
438		}
439	
440		return c.JSON(http.StatusCreated, map[string]interface{}{"interest": interest})
441	}
