27	// HandleLogin handles POST /auth/login.
28	func (s *Service) HandleLogin(c echo.Context) error {
29		var req loginRequest
30		if err := c.Bind(&req); err != nil {
31			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
32		}
33	
34		if req.Username == "" || req.Password == "" {
35			return httpx.NewValidationError(map[string][]string{
36				"username": {"Username is required."},
37				"password": {"Password is required."},
38			})
39		}
40	
41		user, err := s.Authenticate(c.Request().Context(), req.Username, req.Password)
42		if err != nil {
43			return err
44		}
45		if user == nil {
46			s.audit.Log(c.Request().Context(), audit.Event{
47				EventType:    "failed_login",
48				ResourceType: "auth",
49				Metadata:     map[string]interface{}{"username": req.Username},
50			})
51			return httpx.NewAPIError(http.StatusUnauthorized, "invalid_credentials", "Invalid username or password.")
52		}
53	
54		token, err := s.CreateSession(c.Request().Context(), user.ID)
55		if err != nil {
56			return err
57		}
58	
59		s.SetSessionCookie(c, token)
60	
61		s.audit.Log(c.Request().Context(), audit.Event{
62			EventType:    "login",
63			ActorID:      user.ID,
64			ResourceType: "auth",
65		})
66	
67		return c.JSON(http.StatusOK, userResponse{User: user})
68	}
