70	// HandleLogout handles POST /auth/logout.
71	func (s *Service) HandleLogout(c echo.Context) error {
72		token := s.GetSessionToken(c)
73		if token != "" {
74			_ = s.InvalidateSession(c.Request().Context(), token)
75		}
76	
77		s.ClearSessionCookie(c)
78	
79		user := UserFromContext(c)
80		if user != nil {
81			s.audit.Log(c.Request().Context(), audit.Event{
82				EventType:    "logout",
83				ActorID:      user.ID,
84				ResourceType: "auth",
85			})
86		}
87	
88		return c.JSON(http.StatusOK, map[string]string{"message": "Logged out."})
89	}
90	
91	// HandleMe handles GET /auth/me.
92	func (s *Service) HandleMe(c echo.Context) error {
93		user := UserFromContext(c)
94		return c.JSON(http.StatusOK, userResponse{User: user})
95	}
96	
97	// HandleBootstrapAdmin handles POST /auth/bootstrap-admin.
98	func (s *Service) HandleBootstrapAdmin(c echo.Context) error {
99		var req bootstrapRequest
100		if err := c.Bind(&req); err != nil {
101			return httpx.NewAPIError(http.StatusBadRequest, "bad_request", "Invalid request body.")
102		}
103	
104		fieldErrors := map[string][]string{}
105		if req.Username == "" {
106			fieldErrors["username"] = []string{"Username is required."}
107		}
108		if req.Password == "" {
109			fieldErrors["password"] = []string{"Password is required."}
110		} else if len(req.Password) < 8 {
111			fieldErrors["password"] = []string{"Password must be at least 8 characters."}
112		}
113		if req.Email == "" {
114			fieldErrors["email"] = []string{"Email is required."}
115		}
116		if len(fieldErrors) > 0 {
117			return httpx.NewValidationError(fieldErrors)
118		}
119	
120		user, err := s.BootstrapAdmin(c.Request().Context(), req.Username, req.Password, req.Email)
121		if err != nil {
122			return err
123		}
124	
125		s.audit.Log(c.Request().Context(), audit.Event{
126			EventType:    "bootstrap_admin",
127			ActorID:      user.ID,
128			ResourceType: "auth",
129		})
130	
131		return c.JSON(http.StatusCreated, userResponse{User: user})
132	}
