19	// --- Encryption wired into real customer profile path ---
20	
21	func TestEncryptedCustomerPhone(t *testing.T) {
22		db := getTestDB(t)
23		_, _ = db.Exec("DELETE FROM auth_sessions")
24	
25		key, err := crypto.Key()
26		if err != nil {
27			t.Skipf("ENCRYPTION_KEY not set: %v", err)
28		}
29	
30		e := newServer(db)
31		customerCookie := loginAs(t, e, "customer", "customer123")
32	
33		phone := "+1-555-867-5309"
34		body := fmt.Sprintf(`{"phone":"%s"}`, phone)
35		req := httptest.NewRequest(http.MethodPatch, "/api/v1/customer/profile", strings.NewReader(body))
36		req.Header.Set("Content-Type", "application/json")
37		req.AddCookie(customerCookie)
38		rec := httptest.NewRecorder()
39		e.ServeHTTP(rec, req)
40		if rec.Code != http.StatusOK {
41			t.Fatalf("update customer profile: %d %s", rec.Code, rec.Body.String())
42		}
43	
44		// Verify DB stores ciphertext, not plaintext
45		var rawBytes []byte
46		err = db.QueryRow(`SELECT phone_encrypted FROM customer_profiles WHERE user_id = (SELECT id FROM users WHERE username='customer')`).Scan(&rawBytes)
47		if err != nil {
48			t.Fatalf("query phone: %v", err)
49		}
50		if rawBytes == nil || len(rawBytes) == 0 {
51			t.Fatal("phone_encrypted is null/empty")
52		}
53		storedHex := string(rawBytes)
54		if storedHex == phone {
55			t.Fatal("phone_encrypted contains plaintext")
56		}
57	
58		// Read back via real GET endpoint
59		req = httptest.NewRequest(http.MethodGet, "/api/v1/customer/profile", nil)
60		req.AddCookie(customerCookie)
61		rec = httptest.NewRecorder()
62		e.ServeHTTP(rec, req)
63		if rec.Code != http.StatusOK {
64			t.Fatalf("get customer profile: %d %s", rec.Code, rec.Body.String())
65		}
66	
67		var resp map[string]interface{}
68		json.Unmarshal(rec.Body.Bytes(), &resp)
69		profile := resp["profile"].(map[string]interface{})
70		if profile["phone"] != phone {
71			t.Fatalf("decrypted phone mismatch: got %q want %q", profile["phone"], phone)
72		}
73	
74		// Direct decrypt of DB value also works
75		decrypted, err := crypto.Decrypt(key, storedHex)
76		if err != nil {
77			t.Fatalf("direct decrypt: %v", err)
78		}
79		if decrypted != phone {
80			t.Fatalf("direct decrypt mismatch: got %q want %q", decrypted, phone)
81		}
82	}
