1	package interests
2	
3	import (
4		"context"
5		"database/sql"
6		"fmt"
7		"net/http"
8	
9		"fieldserve/internal/audit"
10		"fieldserve/internal/auth"
11		"fieldserve/internal/blocks"
12		"fieldserve/internal/platform/httpx"
13	
14		"github.com/labstack/echo/v4"
15	)
16	
17	// Interest represents a customer-to-provider interest expression.
18	type Interest struct {
19		ID         string `json:"id"`
20		CustomerID string `json:"customer_id"`
21		ProviderID string `json:"provider_id"`
22		ServiceID  string `json:"service_id"`
23		Status     string `json:"status"`
24		CreatedAt  string `json:"created_at"`
25		UpdatedAt  string `json:"updated_at"`
26	}
27	
28	// StatusEvent represents a status change in the interest lifecycle.
29	type StatusEvent struct {
30		ID        string  `json:"id"`
31		OldStatus *string `json:"old_status"`
32		NewStatus string  `json:"new_status"`
33		CreatedAt string  `json:"created_at"`
34	}
35	
36	// Service provides interest management operations.
37	type Service struct {
38		db     *sql.DB
39		audit  *audit.Service
40		blocks *blocks.Service
41	}
42	
43	// NewService creates a new interests service.
44	func NewService(db *sql.DB, audit *audit.Service, blocks *blocks.Service) *Service {
45		return &Service{db: db, audit: audit, blocks: blocks}
46	}
47	
48	// GetCustomerProfileID resolves a user ID to its customer_profiles.id.
49	func (s *Service) GetCustomerProfileID(ctx context.Context, userID string) (string, error) {
50		var profileID string
51		err := s.db.QueryRowContext(ctx,
52			`SELECT id FROM customer_profiles WHERE user_id=$1`, userID,
53		).Scan(&profileID)
54		if err == sql.ErrNoRows {
55			return "", httpx.NewNotFoundError("Customer profile not found.")
56		}
57		if err != nil {
58			return "", fmt.Errorf("interests: get customer profile: %w", err)
59		}
60		return profileID, nil
61	}
62	
63	// GetProviderProfileID resolves a user ID to its provider_profiles.id.
64	func (s *Service) GetProviderProfileID(ctx context.Context, userID string) (string, error) {
65		var profileID string
66		err := s.db.QueryRowContext(ctx,
67			`SELECT id FROM provider_profiles WHERE user_id=$1`, userID,
68		).Scan(&profileID)
69		if err == sql.ErrNoRows {
70			return "", httpx.NewNotFoundError("Provider profile not found.")
71		}
72		if err != nil {
73			return "", fmt.Errorf("interests: get provider profile: %w", err)
74		}
75		return profileID, nil
76	}
77	
78	// GetProviderUserID resolves a provider_profiles.id to its user_id.
79	func (s *Service) GetProviderUserID(ctx context.Context, providerProfileID string) (string, error) {
80		var userID string
81		err := s.db.QueryRowContext(ctx,
82			`SELECT user_id FROM provider_profiles WHERE id=$1`, providerProfileID,
83		).Scan(&userID)
84		if err == sql.ErrNoRows {
85			return "", httpx.NewNotFoundError("Provider not found.")
