108	// Submit creates a new interest from a customer to a provider for a service.
109	func (s *Service) Submit(ctx context.Context, customerProfileID, providerProfileID, serviceID, actorID string) (*Interest, error) {
110		// Resolve user IDs for block check
111		customerUserID, err := s.GetCustomerUserID(ctx, customerProfileID)
112		if err != nil {
113			return nil, err
114		}
115		providerUserID, err := s.GetProviderUserID(ctx, providerProfileID)
116		if err != nil {
117			return nil, err
118		}
119	
120		// Validate that the service belongs to the specified provider
121		var actualProviderID string
122		err = s.db.QueryRowContext(ctx,
123			`SELECT provider_id FROM services WHERE id=$1`, serviceID,
124		).Scan(&actualProviderID)
125		if err == sql.ErrNoRows {
126			return nil, httpx.NewValidationError(map[string][]string{
127				"service_id": {"Service not found."},
128			})
129		}
130		if err != nil {
131			return nil, fmt.Errorf("interests: validate service provider: %w", err)
132		}
133		if actualProviderID != providerProfileID {
134			return nil, httpx.NewValidationError(map[string][]string{
135				"service_id": {"Service does not belong to the specified provider."},
136			})
137		}
138	
139		// Check blocks
140		blocked, err := s.blocks.IsBlocked(ctx, customerUserID, providerUserID)
141		if err != nil {
142			return nil, err
143		}
144		if blocked {
145			return nil, httpx.NewForbiddenError("blocked")
146		}
147	
148		// Check duplicate within 7 days
149		var count int
150		err = s.db.QueryRowContext(ctx,
151			`SELECT COUNT(*) FROM interests WHERE customer_id=$1 AND provider_id=$2 AND status IN ('submitted','accepted') AND created_at > NOW() - INTERVAL '7 days'`,
152			customerProfileID, providerProfileID,
153		).Scan(&count)
154		if err != nil {
155			return nil, fmt.Errorf("interests: check duplicate: %w", err)
156		}
157		if count > 0 {
158			return nil, &echo.HTTPError{
159				Code: http.StatusConflict,
160				Message: httpx.APIError{
161					Error: httpx.ErrorBody{
162						Code:    "duplicate_interest",
163						Message: "An active interest already exists for this provider.",
164						FieldErrors: map[string][]string{
165							"provider_id": {"Only one active interest is allowed within 7 days."},
166						},
167					},
168				},
169			}
170		}
171	
172		// Insert interest
173		var interest Interest
174		err = s.db.QueryRowContext(ctx,
175			`INSERT INTO interests (customer_id, provider_id, service_id) VALUES ($1, $2, $3) RETURNING id, customer_id, provider_id, service_id, status, created_at::text, updated_at::text`,
176			customerProfileID, providerProfileID, serviceID,
177		).Scan(&interest.ID, &interest.CustomerID, &interest.ProviderID, &interest.ServiceID, &interest.Status, &interest.CreatedAt, &interest.UpdatedAt)
178		if err != nil {
179			return nil, fmt.Errorf("interests: insert: %w", err)
180		}
181	
182		// Insert initial status event
183		_, err = s.db.ExecContext(ctx,
184			`INSERT INTO interest_status_events (interest_id, old_status, new_status) VALUES ($1, NULL, 'submitted')`,
185			interest.ID,
186		)
187		if err != nil {
188			return nil, fmt.Errorf("interests: insert status event: %w", err)
189		}
190	
191		// Audit
192		s.audit.Log(ctx, audit.Event{
193			EventType:    "interest_submitted",
194			ActorID:      actorID,
195			ResourceType: "interest",
196			ResourceID:   interest.ID,
197			Metadata: map[string]interface{}{
198				"customer_id": customerProfileID,
199				"provider_id": providerProfileID,
200				"service_id":  serviceID,
201			},
202		})
203	
204		return &interest, nil
205	}
