423	// HandleCustomerSubmit handles POST /customer/interests.
424	func (s *Service) HandleCustomerSubmit(c echo.Context) error {
425		user := auth.UserFromContext(c)
426		if user == nil {
427			return httpx.NewAPIError(http.StatusUnauthorized, "unauthenticated", "Authentication required.")
428		}
429	
430		var body struct {
431			ServiceID  string `json:"service_id"`
432			ProviderID string `json:"provider_id"`
433		}
434		if err := c.Bind(&body); err != nil {
435			return httpx.NewValidationError(map[string][]string{"body": {"Invalid request body."}})
436		}
437	
438		fieldErrors := map[string][]string{}
439		if body.ServiceID == "" {
440			fieldErrors["service_id"] = []string{"Service ID is required."}
441		}
442		if body.ProviderID == "" {
443			fieldErrors["provider_id"] = []string{"Provider ID is required."}
444		}
445		if len(fieldErrors) > 0 {
446			return httpx.NewValidationError(fieldErrors)
447		}
448	
449		cpID, err := s.GetCustomerProfileID(c.Request().Context(), user.ID)
450		if err != nil {
451			return err
452		}
453	
454		interest, err := s.Submit(c.Request().Context(), cpID, body.ProviderID, body.ServiceID, user.ID)
455		if err != nil {
456			return err
457		}
458	
459		return c.JSON(http.StatusCreated, map[string]interface{}{"interest": interest})
460	}
